const BASE_URL = 'http://127.0.0.1:8005';

export const registerUser = async (userData) => {
    const response = await fetch(`${BASE_URL}/api/v1/auth/register`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(userData)
    });
    return response.json();
};

export const createProject = async (projectData) => {
    const response = await fetch(`${BASE_URL}/api/v1/projects`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(projectData)
    });
    return response.json();
};

export const getProjects = async () => {
    const response = await fetch(`${BASE_URL}/api/v1/projects`);
    return response.json();
};

export const changePassword = async (passwordData) => {
    const response = await fetch(`${BASE_URL}/api/v1/auth/change-password`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(passwordData)
    });
    return response.json();
};

// This object makes it compatible with: import api from '../api'
const api = { 
    registerUser, 
    createProject, 
    getProjects, 
    changePassword 
};

export default api;
